  ('elementary-8b44517b-moex-00289', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '下列何者非屬團體協約法第6條第2項所定「無正當理由」之情形？', '["拒絕提供協商所必要之資料", "對於他方提出合理適當之協商內容、時間、地點及進行方式，拒絕進行協商", "未於60日內針對協商書面通知提出對應方案，並進行協商", "雖參與協商，但完全拒絕他方所提之任何一項變更現有勞動條件之要求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "664e5dd214da", "answer_pdf_sha1": "920fc8b6abca", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
