  ('elementary-8b44517b-moex-00293', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依性別平等工作法第31條之規定，為使雇主應就其對受僱者或求職者差別待遇之「非性別、性傾向因素， 或該受僱者或求職者所從事工作之特定性別因素」，負舉證責任，下列敘述何者正確？', '["受僱者或求職者應先釋明雇主有對其差別待遇之事實", "受僱者或求職者應先負擔完整舉證責任而證明雇主有對其差別待遇之事實", "受僱者或求職者對雇主有無對其差別待遇，無需提出任何事實", "受僱者或求職者對雇主有無對其差別待遇，應先保持緘默"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "664e5dd214da", "answer_pdf_sha1": "920fc8b6abca", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
